function CircleOnPath({
  path,
  circle,
  color,
  duration,
  delay = 0
}: {
  path: { d: string }
  circle: { cx: string; cy: string }
  color: string
  duration: number
  delay?: number
}) {
  const scopeRef = useRef<SVGGElement>(null)
  const totalParticles = 50

  useGSAP(
    () => {
      if (!scopeRef.current) return

      const particles = gsap.utils.toArray<SVGCircleElement>('.segment')
      const localPath = scopeRef.current.querySelector<SVGPathElement>('.path')

      if (!localPath) return

      gsap.set(particles, {
        motionPath: {
          path: localPath,
          align: localPath,
          alignOrigin: [0.5, 0.5],
          end: 0
        }
      })
      gsap.to(particles, {
        motionPath: {
          path: localPath,
          align: localPath,
          alignOrigin: [0.5, 0.5]
        },
        duration,
        delay,
        repeat: -1,
        ease: 'linear',
        stagger: 0.005
      })
    },
    { scope: scopeRef }
  )

  return (
    <g ref={scopeRef}>
      <path className="path" d={path.d} fill="none" strokeWidth={1} />

      {Array.from({ length: totalParticles }).map((_, index) => {
        const factor = (totalParticles - index) / totalParticles

        return (
          <circle
            key={index}
            className="segment"
            r={1}
            fill={index === 0 ? 'var(--colors-white)' : color}
            cx={circle.cx}
            cy={circle.cy}
            opacity={factor}
          />
        )
      })}
    </g>
  )
}
